import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useNavigate } from 'react-router-dom';
import { doctorAPI } from '../services/api';
import { 
  FaSearch, 
  FaFilter, 
  FaStar, 
  FaStarHalfAlt, 
  FaRegStar, 
  FaVideo, 
  FaCalendar,
  FaUserMd,
  FaMapMarkerAlt,
  FaLanguage,
  FaClock,
  FaMicrophone,
  FaTimes,
  FaPhoneSlash,
  FaPhone,
  FaVolumeUp,
  FaVolumeMute,
  FaSyncAlt,
  FaComments
} from 'react-icons/fa';

// Call UI Component
const CallUI = ({ callType, doctor, onEndCall }) => {
  const [callDuration, setCallDuration] = useState(0);
  const [isMuted, setIsMuted] = useState(false);
  const [isCameraOn, setIsCameraOn] = useState(callType === 'video');
  const [isMinimized, setIsMinimized] = useState(false);
  const [isSpeakerOn, setIsSpeakerOn] = useState(true);

  useEffect(() => {
    const timer = setInterval(() => {
      setCallDuration(prev => prev + 1);
    }, 1000);

    return () => clearInterval(timer);
  }, []);

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-90 flex items-center justify-center z-50">
      <div className={`bg-gray-900 rounded-lg shadow-2xl ${isMinimized ? 'w-80 h-60' : 'w-full max-w-4xl h-full max-h-screen'} transition-all duration-300`}>
        {/* Header */}
        <div className="bg-gray-800 p-4 rounded-t-lg flex items-center justify-between">
          <div className="text-white">
            <h3 className="font-semibold">{callType === 'video' ? 'Video Call' : 'Audio Call'} with {doctor?.name}</h3>
            <p className="text-gray-300 text-sm">{doctor?.specialty}</p>
          </div>
          <div className="flex items-center gap-4">
            <span className="text-white font-mono">{formatTime(callDuration)}</span>
            <button
              onClick={() => setIsMinimized(!isMinimized)}
              className="text-gray-400 hover:text-white"
            >
              <FaTimes />
            </button>
          </div>
        </div>

        {/* Call Content */}
        <div className={`p-6 ${isMinimized ? 'h-32' : 'flex-1'} flex items-center justify-center`}>
          {callType === 'video' ? (
            <div className="relative w-full h-full bg-gray-800 rounded-lg flex items-center justify-center">
              {isCameraOn ? (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 w-full h-full">
                  {/* Doctor's video placeholder */}
                  <div className="bg-gray-700 rounded-lg flex flex-col items-center justify-center text-white">
                    <div className="w-24 h-24 bg-blue-600 rounded-full flex items-center justify-center mb-2">
                      <span className="text-2xl font-bold">{doctor?.name?.charAt(0)}</span>
                    </div>
                    <p className="font-medium">{doctor?.name}</p>
                  </div>
                  {/* User's video placeholder */}
                  <div className="bg-gray-600 rounded-lg flex flex-col items-center justify-center text-white">
                    <div className="w-24 h-24 bg-green-600 rounded-full flex items-center justify-center mb-2">
                      <span className="text-2xl font-bold">You</span>
                    </div>
                    <p className="font-medium">You</p>
                  </div>
                </div>
              ) : (
                <div className="text-white text-center">
                  <div className="w-32 h-32 bg-gray-600 rounded-full flex items-center justify-center mx-auto mb-4">
                    <span className="text-4xl font-bold">{doctor?.name?.charAt(0)}</span>
                  </div>
                  <p className="text-xl font-medium">{doctor?.name}</p>
                  <p className="text-gray-300">Camera is off</p>
                </div>
              )}
            </div>
          ) : (
            <div className="text-white text-center">
              <div className="w-32 h-32 bg-green-600 rounded-full flex items-center justify-center mx-auto mb-4">
                <FaMicrophone className="text-4xl" />
              </div>
              <p className="text-xl font-medium">{doctor?.name}</p>
              <p className="text-gray-300">Audio Call</p>
            </div>
          )}
        </div>

        {/* Controls */}
        <div className="bg-gray-800 p-4 rounded-b-lg flex items-center justify-center gap-4">
          {/* Mute Toggle */}
          <button
            onClick={() => setIsMuted(!isMuted)}
            className={`w-12 h-12 rounded-full flex items-center justify-center transition-colors ${
              isMuted ? 'bg-red-600 hover:bg-red-700' : 'bg-gray-600 hover:bg-gray-700'
            }`}
          >
            <FaMicrophone className={`text-white ${isMuted ? 'opacity-50' : ''}`} />
          </button>

          {/* Camera Toggle (Video only) */}
          {callType === 'video' && (
            <button
              onClick={() => setIsCameraOn(!isCameraOn)}
              className={`w-12 h-12 rounded-full flex items-center justify-center transition-colors ${
                !isCameraOn ? 'bg-red-600 hover:bg-red-700' : 'bg-gray-600 hover:bg-gray-700'
              }`}
            >
              <FaVideo className={`text-white ${!isCameraOn ? 'opacity-50' : ''}`} />
            </button>
          )}

          {/* Switch Camera (Video only) */}
          {callType === 'video' && (
            <button
              className="w-12 h-12 rounded-full bg-gray-600 hover:bg-gray-700 flex items-center justify-center transition-colors"
              aria-label="Switch camera"
            >
              <FaSyncAlt className="text-white" />
            </button>
          )}

          {/* Speaker toggle (Audio only) */}
          {callType === 'audio' && (
            <button
              onClick={() => setIsSpeakerOn(!isSpeakerOn)}
              className={`w-12 h-12 rounded-full flex items-center justify-center transition-colors ${
                isSpeakerOn ? 'bg-gray-600 hover:bg-gray-700' : 'bg-red-600 hover:bg-red-700'
              }`}
              aria-label="Toggle speaker"
            >
              {isSpeakerOn ? (
                <FaVolumeUp className="text-white" />
              ) : (
                <FaVolumeMute className="text-white" />
              )}
            </button>
          )}

          {/* Optional in-call chat (placeholder) */}
          <button
            className="w-12 h-12 rounded-full bg-gray-600 hover:bg-gray-700 flex items-center justify-center transition-colors"
            aria-label="Open chat (placeholder)"
          >
            <FaComments className="text-white" />
          </button>

          {/* End Call */}
          <button
            onClick={onEndCall}
            className="w-12 h-12 rounded-full bg-red-600 hover:bg-red-700 flex items-center justify-center transition-colors"
          >
            <FaPhoneSlash className="text-white" />
          </button>
        </div>
      </div>
    </div>
  );
};

const Home = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const [doctors, setDoctors] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedSpecialty, setSelectedSpecialty] = useState('');
  const [availableOnly, setAvailableOnly] = useState(false);
  const [showConsultModal, setShowConsultModal] = useState(false);
  const [showCallUI, setShowCallUI] = useState(false);
  const [callType, setCallType] = useState('');
  const [selectedDoctorForCall, setSelectedDoctorForCall] = useState(null);

  // Dummy data for demonstration
  const dummyDoctors = [
    {
      id: '1',
      name: 'Dr. Rajesh Kumar',
      specialty: 'Cardiology',
      qualifications: 'MBBS, MD Cardiology',
      experience_years: 15,
      consultation_fee: 500,
      is_available: true,
      languages: 'English, Hindi, Punjabi',
      rating: 4.8,
      total_consultations: 1200,
      profile_image: null
    },
    {
      id: '2',
      name: 'Dr. Priya Sharma',
      specialty: 'Pediatrics',
      qualifications: 'MBBS, MD Pediatrics',
      experience_years: 10,
      consultation_fee: 400,
      is_available: true,
      languages: 'English, Hindi',
      rating: 4.6,
      total_consultations: 800,
      profile_image: null
    },
    {
      id: '3',
      name: 'Dr. Harpreet Singh',
      specialty: 'General Medicine',
      qualifications: 'MBBS, MD Internal Medicine',
      experience_years: 12,
      consultation_fee: 350,
      is_available: false,
      languages: 'English, Hindi, Punjabi',
      rating: 4.5,
      total_consultations: 950,
      profile_image: null
    },
    {
      id: '4',
      name: 'Dr. Sunita Devi',
      specialty: 'Gynecology',
      qualifications: 'MBBS, MS Gynecology',
      experience_years: 8,
      consultation_fee: 450,
      is_available: true,
      languages: 'English, Hindi, Punjabi',
      rating: 4.7,
      total_consultations: 600,
      profile_image: null
    }
  ];

  useEffect(() => {
    fetchDoctors();
  }, []);

  const fetchDoctors = async () => {
    try {
      setLoading(true);
      // For demo purposes, we'll use dummy data
      // In production, uncomment the API call below
      // const response = await doctorAPI.getAll();
      // setDoctors(response.data);
      
      // Simulate API delay
      setTimeout(() => {
        setDoctors(dummyDoctors);
        setLoading(false);
      }, 1000);
    } catch (error) {
      console.error('Error fetching doctors:', error);
      setError('Failed to load doctors');
      setDoctors(dummyDoctors); // Fallback to dummy data
      setLoading(false);
    }
  };

  const filteredDoctors = doctors.filter(doctor => {
    const matchesSearch = doctor.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         doctor.specialty.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesSpecialty = !selectedSpecialty || doctor.specialty === selectedSpecialty;
    const matchesAvailability = !availableOnly || doctor.is_available;
    
    return matchesSearch && matchesSpecialty && matchesAvailability;
  });

  const specialties = [...new Set(doctors.map(doctor => doctor.specialty))];

  const renderStars = (rating) => {
    const stars = [];
    const fullStars = Math.floor(rating);
    const hasHalfStar = rating % 1 !== 0;
    const emptyStars = 5 - fullStars - (hasHalfStar ? 1 : 0);

    for (let i = 0; i < fullStars; i++) {
      stars.push(<FaStar key={`full-${i}`} className="star" />);
    }
    
    if (hasHalfStar) {
      stars.push(<FaStarHalfAlt key="half" className="star" />);
    }
    
    for (let i = 0; i < emptyStars; i++) {
      stars.push(<FaRegStar key={`empty-${i}`} className="star empty" />);
    }

    return stars;
  };

  const handleConsultNow = (doctorId) => {
    const doctor = filteredDoctors.find(d => d.id === doctorId);
    setSelectedDoctorForCall(doctor);
    setShowConsultModal(true);
  };

  const handleBookAppointment = (doctorId) => {
    const doctor = filteredDoctors.find(d => d.id === doctorId);
    // Navigate to appointments page with doctor data in state
    navigate('/appointments', { 
      state: { selectedDoctor: doctor }
    });
  };

  if (loading) {
    return (
      <div className="container mx-auto px-4 py-8">
        <div className="flex items-center justify-center min-h-64">
          <div className="loading"></div>
          <span className="ml-2">Loading doctors...</span>
        </div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8 text-center">
      {/* Header */}
      <div className="mb-8">
        <h1 className="text-4xl font-bold text-gray-900 mb-2">
          Welcome to Helio
        </h1>
        <p className="text-lg text-gray-600">
          Your Health, Our Priority.
        </p>
      </div>

      {/* Search and Filters */}
      <div className="bg-white rounded-lg shadow-md border p-6 mb-8 max-w-4xl mx-auto">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 items-center">
          {/* Search */}
          <div className="relative">
            <FaSearch className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400" />
            <input
              type="text"
              placeholder={`${t('search')} ${t('doctors').toLowerCase()}...`}
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="input pl-12 w-full"
            />
          </div>

          {/* Specialty Filter */}
          <div className="relative">
            <FaFilter className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400" />
            <select
              value={selectedSpecialty}
              onChange={(e) => setSelectedSpecialty(e.target.value)}
              className="input pl-12 w-full"
            >
              <option value="">All Specialties</option>
              {specialties.map(specialty => (
                <option key={specialty} value={specialty}>{specialty}</option>
              ))}
            </select>
          </div>

          {/* Availability Filter */}
          <div className="flex items-center justify-center gap-3">
            <input
              type="checkbox"
              id="availableOnly"
              checked={availableOnly}
              onChange={(e) => setAvailableOnly(e.target.checked)}
              className="rounded border-gray-300 text-primary-color focus:ring-primary-color"
            />
            <label htmlFor="availableOnly" className="text-sm font-medium text-gray-700">
              {t('available')} only
            </label>
          </div>
        </div>
      </div>

      {/* Error Message */}
      {error && (
        <div className="bg-red-100 border border-red-300 text-red-700 p-4 rounded-lg mb-6 max-w-4xl mx-auto">
          {error}
        </div>
      )}

      {/* Doctors Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
        {filteredDoctors.map((doctor) => (
          <div key={doctor.id} className="card hover:shadow-xl transition-all duration-300 flex flex-col h-full">
            {/* Doctor Header */}
            <div className="flex-grow">
              <div className="flex items-center gap-4 mb-4">
                <div className="w-20 h-20 bg-gradient-to-br from-blue-500 to-blue-700 rounded-full flex items-center justify-center text-white text-3xl font-bold">
                  {doctor.profile_image ? (
                    <img 
                      src={doctor.profile_image} 
                      alt={doctor.name}
                      className="w-full h-full rounded-full object-cover"
                    />
                  ) : (
                    <FaUserMd />
                  )}
                </div>
                
                <div className="flex-1 text-left">
                  <h3 className="font-bold text-xl text-gray-900">{doctor.name}</h3>
                  <p className="text-blue-600 font-semibold">{doctor.specialty}</p>
                </div>
              </div>

              {/* Doctor Info */}
              <div className="space-y-3 mb-6 text-left">
                <p className="text-gray-700">{doctor.qualifications}</p>
                <div className="flex items-center justify-between text-sm">
                  <div className="flex items-center gap-2">
                    <FaClock className="text-gray-500" />
                    <span className="text-gray-700">
                      {doctor.experience_years} years exp.
                    </span>
                  </div>
                  <div className="flex items-center gap-1">
                    <div className="rating flex items-center text-yellow-500">
                      {renderStars(doctor.rating)}
                    </div>
                    <span className="text-gray-600 ml-1">
                      ({doctor.total_consultations})
                    </span>
                  </div>
                </div>

                <div className="flex items-center gap-2 text-sm">
                  <FaLanguage className="text-gray-500" />
                  <span className="text-gray-700">{doctor.languages}</span>
                </div>
              </div>
            </div>

            {/* Action Buttons */}
            <div className="mt-auto pt-4 border-t border-gray-200">
              <div className="grid grid-cols-3 gap-3">
                {/* Video Call */}
                <button
                  onClick={() => {
                    setSelectedDoctorForCall(doctor);
                    setShowConsultModal(false);
                    setCallType('video');
                    setShowCallUI(true);
                  }}
                  disabled={!doctor.is_available}
                  className="h-11 w-full flex items-center justify-center gap-2 rounded-lg bg-green-600 hover:bg-green-700 text-white transition-colors focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2"
                  aria-label={`Consult ${doctor.name} by video call`}
                >
                  <FaVideo />
                  <span className="text-sm font-medium">Video</span>
                </button>

                {/* Audio Call */}
                <button
                  onClick={() => {
                    setSelectedDoctorForCall(doctor);
                    setShowConsultModal(false);
                    setCallType('audio');
                    setShowCallUI(true);
                  }}
                  disabled={!doctor.is_available}
                  className="h-11 w-full flex items-center justify-center gap-2 rounded-lg bg-green-600 hover:bg-green-700 text-white transition-colors focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2"
                  aria-label={`Consult ${doctor.name} by audio call`}
                >
                  <FaPhone />
                  <span className="text-sm font-medium">Audio</span>
                </button>

                {/* Book Appointment */}
                <button
                  onClick={() => handleBookAppointment(doctor.id)}
                  className="h-11 w-full flex items-center justify-center gap-2 rounded-lg bg-white border border-gray-300 text-gray-700 hover:border-blue-400 hover:text-blue-600 transition-colors focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2"
                  aria-label={`Book appointment with ${doctor.name}`}
                >
                  <FaCalendar />
                  <span className="text-sm font-medium">Book</span>
                </button>
              </div>
              <div
                className={`mt-2 text-center text-sm font-medium ${
                  doctor.is_available ? 'text-green-600' : 'text-red-600'
                }`}
              >
                {doctor.is_available ? t('available') : t('unavailable')}
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* No Results */}
      {filteredDoctors.length === 0 && !loading && (
        <div className="text-center py-12">
          <FaUserMd className="mx-auto text-6xl text-gray-300 mb-4" />
          <h3 className="text-xl font-medium text-gray-900 mb-2">No doctors found</h3>
          <p className="text-gray-600">
            Try adjusting your search criteria or filters
          </p>
        </div>
      )}

      {/* Consultation Type Modal */}
      {showConsultModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg shadow-xl p-6 w-96 max-w-95vw">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-xl font-semibold text-gray-900">Choose Consultation Type</h3>
              <button
                onClick={() => setShowConsultModal(false)}
                className="text-gray-400 hover:text-gray-600"
              >
                <FaTimes className="text-xl" />
              </button>
            </div>
            
            {selectedDoctorForCall && (
              <div className="mb-6 p-4 bg-gray-50 rounded-lg">
                <h4 className="font-medium text-gray-900">{selectedDoctorForCall.name}</h4>
                <p className="text-gray-600">{selectedDoctorForCall.specialty}</p>
              </div>
            )}

            <div className="space-y-3">
              <button
                onClick={() => {
                  setCallType('video');
                  setShowConsultModal(false);
                  setShowCallUI(true);
                }}
                className="w-full flex items-center justify-center gap-3 p-4 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
              >
                <FaVideo className="text-xl" />
                <span className="font-medium">Video Call</span>
              </button>
              
              <button
                onClick={() => {
                  setCallType('audio');
                  setShowConsultModal(false);
                  setShowCallUI(true);
                }}
                className="w-full flex items-center justify-center gap-3 p-4 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors"
              >
                <FaMicrophone className="text-xl" />
                <span className="font-medium">Audio Call</span>
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Call UI Modal */}
      {showCallUI && <CallUI callType={callType} doctor={selectedDoctorForCall} onEndCall={() => {
        setShowCallUI(false);
        setCallType('');
        setSelectedDoctorForCall(null);
      }} />}
    </div>
  );
};

export default Home;
